CREATE TABLE IF NOT EXISTS horse_clubs (
    id SERIAL PRIMARY KEY,
    name VARCHAR(255) NOT NULL,
    country VARCHAR(100) NOT NULL,
    city VARCHAR(100),
    address TEXT,
    zip_code VARCHAR(20),
    phone VARCHAR(50) NOT NULL,
    website TEXT,
    latitude DECIMAL(10, 8),
    longitude DECIMAL(11, 8),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE INDEX IF NOT EXISTS idx_country ON horse_clubs(country);
CREATE INDEX IF NOT EXISTS idx_city ON horse_clubs(city);

TRUNCATE TABLE horse_clubs;

